1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE = 60;
4	const COMPONENT_BASE = 25;
5	const FIRST_INS_SURCHARGE = 0.1;
6	const CURSE_SURCHARGE = 0.5;
7	const HIGH_ENCH_SURCHARGE = 0.3;
8	const HIGH_ENCH_THRESHOLD = 5;
9	const LOYALTY_DISCOUNT = 0.2;
10	const LOYALTY_THRESHOLD = 2;
11	
12	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = {
24	  type: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	  material?: string;
28	};
29	
30	const baseForItem = (item: Item): number =>
31	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
32	
33	const isComponent = (item: Item): boolean =>
34	  COMPONENT_TYPES.has(item.type);
35	
36	const itemModifierSum = (item: Item): number => {
37	  let mod = FIRST_INS_SURCHARGE;
38	  if (item.cursed) mod += CURSE_SURCHARGE;
39	  if ((item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD) mod += HIGH_ENCH_SURCHARGE;
40	  return mod;
41	};
42	
43	const itemCharge = (item: Item): number =>
44	  baseForItem(item) * (1 + itemModifierSum(item));
45	
46	const countByType = (items: Item[]): Record<string, number> => {
47	  const counts: Record<string, number> = {};
48	  for (const item of items) {
49	    counts[item.type] = (counts[item.type] ?? 0) + 1;
50	  }
51	  return counts;
52	};
53	
54	const componentsCharge = (items: Item[]): number => {
55	  const componentItems = items.filter(isComponent);
56	  const counts = countByType(componentItems);
57	  let total = 0;
58	  for (const type in counts) {
59	    const count = counts[type];
60	    if (count === BLOCK_SIZE) {
61	      total += BLOCK_PRICE * (1 + FIRST_INS_SURCHARGE);
62	    } else {
63	      total += count * COMPONENT_BASE * (1 + FIRST_INS_SURCHARGE);
64	    }
65	  }
66	  return total;
67	};
68	
69	const componentsBase = (items: Item[]): number => {
70	  const componentItems = items.filter(isComponent);
71	  const counts = countByType(componentItems);
72	  let total = 0;
73	  for (const type in counts) {
74	    const count = counts[type];
75	    total += count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_BASE;
76	  }
77	  return total;
78	};
79	
80	const nonComponentsCharge = (items: Item[]): number =>
81	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + itemCharge(item), 0);
82	
83	const nonComponentsBase = (items: Item[]): number =>
84	  items.filter((item) => !isComponent(item)).reduce((sum, item) => sum + baseForItem(item), 0);
85	
86	export function quote(input: any): unknown {
87	  const items: Item[] = input.items;
88	  const itemTotal = nonComponentsCharge(items) + componentsCharge(items);
89	  const policyBase = nonComponentsBase(items) + componentsBase(items);
90	  const years = input.customer?.yearsWithMHPCO ?? 0;
91	  let policyModifiers = 0;
92	  if (years >= LOYALTY_THRESHOLD) policyModifiers -= LOYALTY_DISCOUNT;
93	  const policyAdjustment = policyBase * policyModifiers;
94	  const raw = itemTotal + policyAdjustment + PROCESSING_FEE;
95	  const premium = Math.ceil(Math.round(raw * 1e8) / 1e8);
96	  return { premium };
97	}
98	
99	export function claim(_input: unknown): unknown {
100	  throw new Error("not implemented");
101	}
